SELECT [ReportVendutoComprato-NonProiettato-Acquisti].Linea, [ReportVendutoComprato-NonProiettato-Acquisti].Articolo, [ReportVendutoComprato-NonProiettato-Acquisti].CodiceColore, [ReportVendutoComprato-NonProiettato-Acquisti].Colore, [ReportVendutoComprato-NonProiettato-Acquisti].Marchio, [ReportVendutoComprato-NonProiettato-Acquisti].Stagione, [ReportVendutoComprato-NonProiettato-Acquisti].[delete reason], [ReportVendutoComprato-NonProiettato-Acquisti].paiacomprate, 0 AS PaiaVendute, [ReportVendutoComprato-NonProiettato-Acquisti].Descrizione, [ReportVendutoComprato-NonProiettato-Acquisti].Descrizione2, [ReportVendutoComprato-NonProiettato-Acquisti].FamigliaProdotto, [ReportVendutoComprato-NonProiettato-Acquisti].GenereProdotto, [ReportVendutoComprato-NonProiettato-Acquisti].[Collection Code], [ReportVendutoComprato-NonProiettato-Acquisti].[Vendor No_], [ReportVendutoComprato-NonProiettato-Acquisti].VendorName, [ReportVendutoComprato-NonProiettato-Vendite].[Document Type], [ReportVendutoComprato-NonProiettato-Acquisti].Manufacturer, [ReportVendutoComprato-NonProiettato-Acquisti].ManufacturerName
FROM [ReportVendutoComprato-NonProiettato-Acquisti] LEFT JOIN [ReportVendutoComprato-NonProiettato-Vendite] ON ([ReportVendutoComprato-NonProiettato-Acquisti].CodiceColore = [ReportVendutoComprato-NonProiettato-Vendite].CodiceColore) AND ([ReportVendutoComprato-NonProiettato-Acquisti].Articolo = [ReportVendutoComprato-NonProiettato-Vendite].Articolo)
WHERE ((([ReportVendutoComprato-NonProiettato-Vendite].[Document Type]) Is Null));

